compliant:
// Concept names should follow PascalCase convention
template <class T>
concept Integral = std::is_integral_v<T>; // Compliant

template <class T>
concept MyConcept = requires(T t) { t.size(); }; // Compliant

template <class T>
concept Movable = std::is_move_constructible_v<T>; // Compliant

template <typename T>
concept Serializable = requires(T obj, std::ostream& os) {
    os << obj;
}; // Compliant
